        Library:Notify({Title="COMBOWICK", Description="Не удалось проверить сессию.", Time=5})

    elseif result.status == "allowed" or result.status == "session_active" then
        if result.disabled then
            safeSet(statusLabel, "⛔ Игра отключена")
            safeSet(hintLabel, "Бесплатная версия здесь недоступна. Получите ключ.")
            Library:Notify({Title="COMBOWICK", Description="Бесплатная версия отключена для этой игры. Используйте ключ.", Time=6})
            return
        end
        local token = result.session_token
        if type(token) ~= "string" or #token < 20 then
            safeSet(statusLabel, "Статус: Ошибка")
        else
            safeSet(statusLabel, "Статус: Аутентифицирован")
            Library:Notify({Title="COMBOWICK", Description="Вы аутентифицированы.", Time=3})
            _G.COMBOWICK_FREE   = true
            _G.COMBOWICK_ACTIVE = true
            local remaining = tonumber(result.remaining) or 0
            task.spawn(function()
                while remaining > 0 do
                    local fmt = M.formatTime(remaining)
                    safeSet(timerLabel, string.format("Осталось времени: %s", fmt))
                    safeSet(lSession, string.format("Время сессии: %s", fmt))
                    task.wait(1); remaining = remaining - 1
                end
                safeSet(timerLabel, "Сессия истекла.")
                safeSet(lSession, "Время сессии: истекло")
                _G.COMBOWICK_ACTIVE = false
                pcall(function() Library:Unload() end)
                task.wait(0.5)
                M.reloadExist()
            end)
            local scriptUrl = M.getScriptForGame(token)
            if M.loadFreeScript(scriptUrl, token) then task.wait(2); pcall(function() Library:Unload() end) end
        end

    elseif result.status == "cooldown" then
        local remaining = tonumber(result.remaining) or 0
        safeSet(statusLabel, "Перезарядка")
        safeSet(hintLabel, "Получите 11-часовой ключ или дождитесь окончания перезарядки.")
        Library:Notify({Title="COMBOWICK", Description="У вас перезарядка. Получите ключ, чтобы не ждать.", Time=6})
        task.spawn(function()
            while remaining > 0 do
                local fmt = M.formatTime(remaining)
                safeSet(timerLabel, string.format("Перезарядка: %s", fmt))
                safeSet(lCooldown, string.format("Перезарядка: %s", fmt))
                task.wait(1); remaining = remaining - 1
            end
            safeSet(timerLabel, "Перезарядка завершена.")
            safeSet(lCooldown, "Перезарядка: завершена")
            safeSet(hintLabel, "")
            Library:Notify({Title="COMBOWICK", Description="Перезарядка завершена. Перезагрузка...", Time=3})
            pcall(function() Library:Unload() end)
            task.wait(0.5)
            M.reloadExist()
        end)

    elseif result.status == "throttled" then
        local remaining = tonumber(result.remaining) or 0
        safeSet(statusLabel, "Слишком много запросов")
        safeSet(hintLabel, "Слишком много запросов. Пожалуйста, подождите.")
        Library:Notify({Title="COMBOWICK", Description="Слишком много запросов. Подождите немного.", Time=5})
        task.spawn(function()
            while remaining > 0 do
                safeSet(timerLabel, string.format("Повтор через %s", M.formatTime(remaining)))
                task.wait(1); remaining = remaining - 1
            end
            safeSet(timerLabel, "Перезагрузка...")
            safeSet(hintLabel, "")
            pcall(function() Library:Unload() end)
            task.wait(0.5)
            M.reloadExist()
        end)

    elseif result.status == "disabled" then
        safeSet(statusLabel, "Сервис приостановлен")
        safeSet(hintLabel, "COMBOWICK временно недоступен.")
        Library:Notify({Title="COMBOWICK", Description="Сервис сейчас отключён. Попробуйте позже.", Time=6})

    elseif result.status == "banned" then
        safeSet(statusLabel, "Заблокирован")
        Library:Notify({Title="COMBOWICK", Description="Вы заблокированы.", Time=5})

    elseif result.status == "game_not_allowed" then
        safeSet(statusLabel, "🚫 Игра не поддерживается")
        safeSet(hintLabel, "Эта игра пока не поддерживается. Premium-ключи работают, если доступен скрипт.")
        Library:Notify({Title="COMBOWICK", Description="Эта игра пока не поддерживается.", Time=6})

    else
        safeSet(statusLabel, "Ошибка")
        safeSet(hintLabel, "Не удалось подключиться к серверу. Запустите скрипт заново.")
        Library:Notify({Title="COMBOWICK", Description=tostring(result.message or "Произошла неизвестная ошибка."), Time=5})
    end
end)

